UPDATE words SET example_en_2 = 'She asked the deli to slice the ham thinly.', example_ko_2 = '그녀는 델리에 햄을 얇게 잘라 달라고 부탁했어요.', example_en_3 = 'He cut two thick slices of bread for the sandwich.', example_ko_3 = '그는 샌드위치용으로 빵을 두껍게 두 조각 잘랐어요.', example_en_4 = 'Place each slice of cheese on top of a cracker.', example_ko_4 = '크래커 위에 치즈 한 장씩 올려 주세요.', example_en_5 = 'She sliced the brisket against the grain for tenderness.', example_ko_5 = '그녀는 부드럽게 먹기 위해 양지머리를 결 반대 방향으로 썰었어요.' WHERE id = 'w_cooking_A2_23';

UPDATE words SET example_en_2 = 'She learned to peel vegetables quickly with a good peeler.', example_ko_2 = '그녀는 좋은 필러를 사용해 채소 껍질을 빠르게 벗기는 법을 배웠어요.', example_en_3 = 'He peeled and segmented the orange for the fruit salad.', example_ko_3 = '그는 과일 샐러드를 위해 오렌지 껍질을 벗기고 조각냈어요.', example_en_4 = 'Peel the garlic cloves before mincing them.', example_ko_4 = '마늘을 다지기 전에 껍질을 벗겨 주세요.', example_en_5 = 'Leave the skin on the potatoes for extra nutrition.', example_ko_5 = '영양을 더 섭취하려면 감자 껍질을 그대로 두세요.' WHERE id = 'w_cooking_A2_24';

