UPDATE words SET example_en_2 = 'The waiter served the dessert with a smile.', example_ko_2 = '웨이터는 웃으며 디저트를 가져다주었어요.', example_en_3 = 'She served the pasta with a side of garlic bread.', example_ko_3 = '그녀는 파스타를 마늘빵과 함께 냈어요.', example_en_4 = 'Always serve salad chilled for the best taste.', example_ko_4 = '샐러드는 차갑게 해서 내야 가장 맛있어요.', example_en_5 = 'He served the steak on a warm plate to keep it hot.', example_ko_5 = '그는 스테이크가 식지 않도록 따뜻한 접시에 담아 냈어요.' WHERE id = 'w_cooking_A2_30';

UPDATE words SET example_en_2 = 'The rich flavor of the broth comes from hours of simmering.', example_ko_2 = '육수의 진한 풍미는 오랜 시간 끓인 덕분이에요.', example_en_3 = 'She added lemon zest to brighten the flavor of the dish.', example_ko_3 = '그녀는 요리의 맛을 살리기 위해 레몬 제스트를 더했어요.', example_en_4 = 'He described the flavor as both sweet and slightly bitter.', example_ko_4 = '그는 그 맛을 달콤하면서도 약간 씁쓸하다고 표현했어요.', example_en_5 = 'Fresh herbs add wonderful flavor to any dish.', example_ko_5 = '신선한 허브는 어떤 요리에든 훌륭한 풍미를 더해 줘요.' WHERE id = 'w_cooking_A2_31';

UPDATE words SET example_en_2 = 'The dressing has a pleasant sour taste from the lemon juice.', example_ko_2 = '드레싱은 레몬즙 덕분에 상쾌하게 신맛이 나요.', example_en_3 = 'She added a little honey to balance the sour flavour.', example_ko_3 = '그녀는 신맛을 잡기 위해 꿀을 조금 넣었어요.', example_en_4 = 'This yoghurt is quite sour—perfect for cooking.', example_ko_4 = '이 요거트는 꽤 새요. 요리하기에 딱 맞아요.', example_en_5 = 'Sour cream adds a tangy flavour to tacos.', example_ko_5 = '사워크림은 타코에 새콤한 맛을 더해 줘요.' WHERE id = 'w_cooking_A2_32';

UPDATE words SET example_en_2 = 'She prefers salty snacks over sweet ones.', example_ko_2 = '그녀는 단 간식보다 짭짤한 간식을 더 좋아해요.', example_en_3 = 'The soup was too salty, so she added more water.', example_ko_3 = '수프가 너무 짜서 그녀는 물을 더 넣었어요.', example_en_4 = 'He described the cheese as sharp and salty.', example_ko_4 = '그는 그 치즈를 강렬하고 짭짤하다고 표현했어요.', example_en_5 = 'Salty foods can make you feel thirsty very quickly.', example_ko_5 = '짠 음식을 먹으면 금방 목이 말라요.' WHERE id = 'w_cooking_A2_33';

UPDATE words SET example_en_2 = 'The curry is very spicy—be careful if you are sensitive to heat.', example_ko_2 = '카레가 매우 매워요. 매운 음식에 약하면 조심하세요.', example_en_3 = 'She loves spicy food but always keeps yoghurt nearby.', example_ko_3 = '그녀는 매운 음식을 좋아하지만 항상 요거트를 곁에 둬요.', example_en_4 = 'He added extra chilli to make the sauce spicier.', example_ko_4 = '그는 소스를 더 맵게 만들기 위해 고추를 더 넣었어요.', example_en_5 = 'Korean kimchi is famous for its spicy and tangy flavour.', example_ko_5 = '한국의 김치는 매콤하고 새콤한 맛으로 유명해요.' WHERE id = 'w_cooking_A2_34';

UPDATE words SET example_en_2 = 'A mild flavour is best for young children or sensitive stomachs.', example_ko_2 = '순한 맛은 어린아이나 예민한 위장을 가진 사람에게 가장 좋아요.', example_en_3 = 'She chose a mild cheddar for the sauce.', example_ko_3 = '그녀는 소스에 쓸 순한 체다 치즈를 골랐어요.', example_en_4 = 'The soup has a mild flavour with a hint of garlic.', example_ko_4 = '이 수프는 마늘 향이 살짝 나는 순한 맛이에요.', example_en_5 = 'He prefers mild salsa because he cannot handle spicy food.', example_ko_5 = '그는 매운 음식을 못 먹어서 순한 살사를 즐겨요.' WHERE id = 'w_cooking_A2_35';

